import java.util.Scanner;

class BankAccount {
    private double balance;

    BankAccount(double balance) {
        this.balance = balance;
    }

    // throws — declares that this method might throw an exception
    public void withdraw(double amount) throws Exception {
        if (amount < 0) {
            // throw — actively creates and throws an exception
            throw new IllegalArgumentException("Amount cannot be negative!");
        }

        if (amount > balance) {
            throw new Exception("Insufficient balance! Balance: $" + balance);
        }

        balance -= amount;
        System.out.println("Withdrew $" + amount + ". New balance: $" + balance);
    }

    public double getBalance() {
        return balance;
    }
}

public class ThrowThrowsExample {

    // Propagating exception
    public static void riskyMethod() throws Exception {
        throw new Exception("Risky operation failed!");
    }

    public static void main(String[] args) {
        BankAccount account = new BankAccount(1000);
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter withdrawal amount: $");
        double amount = scanner.nextDouble();

        try {
            account.withdraw(amount);
        } catch (IllegalArgumentException e) {
            System.out.println("Illegal argument: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }

        // Propagating exception with throws
        System.out.println("--- Propagating exception ---");
        try {
            riskyMethod();
        } catch (Exception e) {
            System.out.println("Caught propagated exception: " + e.getMessage());
        }

        scanner.close();
    }
}

