class Product {
    private String name;
    private double price;

    Product(String name, double price) {
        if (name == null || name.trim().isEmpty()) {
            throw new IllegalArgumentException("Product name cannot be empty!");
        }
        if (price < 0) {
            throw new IllegalArgumentException("Product price cannot be negative!");
        }
        this.name = name;
        this.price = price;
    }

    double getDiscountedPrice(double discount) {
        if (discount < 0 || discount > 50) {
            throw new IllegalArgumentException("Discount must be 0-50%!");
        }
        return price * (1 - discount / 100);
    }

    void display() {
        System.out.println("Product: " + name + ", Price: $" + price);
    }
}

public class Main {
    public static void main(String[] args) {
        try {
            Product p1 = new Product("Laptop", 1000);
            p1.display();
            System.out.println("10% discount: $" + p1.getDiscountedPrice(10));

            Product p2 = new Product("", 100);  // Invalid
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }

        try {
            Product p3 = new Product("Phone", -50);  // Invalid
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
